INSERT INTO "public"."livros"
("id", "category_id", "filter_id", "title", "author", "summary", "cover_url", "cover_emoji", "badge", "file_size_label", "external_url", "pdf_url", "epub_url", "is_free", "is_featured", "featured_rank", "estimated_pages", "is_active", "created_at", "updated_at")
VALUES
('a1', 'arte', 'bb6493b8-ad8e-4027-906a-8028a55fa787', 'Grandes Pianistas ao Piano', 'James Francis Cooke', '"Grandes Pianistas e a Arte de Tocar Piano", de James Francis Cooke, é uma coletânea de palestras e conversas pessoais com pianistas renomados, provavelmente escrita no início do século XX. O livro oferece insights sobre a vida e os pensamentos de diversos pianistas a respeito de técnica, interpretação, estilo e expressão ao tocar piano. Apresenta uma rica combinação de anedotas pessoais e conselhos práticos de algumas das figuras mais proeminentes do mundo da música.', 'https://www.gutenberg.org/cache/epub/28026/pg28026.cover.medium.jpg', null, 'free', null, 'https://www.gutenberg.org/cache/epub/28026/pg28000.epub', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-27 23:49:25.649386+00'),
('a10', 'arte', null, 'Um dicionário de vestuário masculino', 'William Henry Baker', '"Um dicionário de vestuário masculino", de William Henry Baker, é um dicionário de referência comercial escrito no início do século XX. Ele compila a terminologia do vestuário masculino e ofícios afins — abrangendo tecidos, alfaiataria, calçados, chapéus, armarinhos e uniformes — combinando definições precisas com gírias do setor e notas práticas. Destinado a comerciantes de roupas, alfaiates, fabricantes e vendedores, promete um léxico envolvente e útil, com apêndices sobre vestimenta adequada e trajes militares. A abertura do dicionário apresenta uma epígrafe bem-humorada, uma dedicatória abrangente aos ofícios de vestuário e um prefácio explicativo que descreve suas origens em um "Dicionário de Roupas" menor, seu objetivo de ser completo e, ao mesmo tempo, acessível, e sua escolha por ortografia simplificada e formato sem pronúncia para economizar espaço. O autor prioriza a praticidade em detrimento do pedantismo, observa que a cobertura incompleta é inevitável e lista extensas fontes (enciclopédias, publicações comerciais e regulamentos de uniformes dos EUA), seguidas de agradecimentos pessoais. Em seguida, começam os verbetes em ordem alfabética, de A até o início de C, definindo vestimentas, tecidos, processos e ferramentas (de alpaca e aiguillette a ponto atrás e trama de cestaria), juntamente com gírias do varejo, equipamentos esportivos e notas detalhadas sobre uniformes militares — tudo apresentado em um tom ágil e, por vezes, espirituoso.', 'https://www.gutenberg.org/cache/epub/76299/pg76299.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/76299/pg76299-images.epub', null, null, true, false, null, null, true, '2026-05-27 23:46:53.158282+00', '2026-05-27 23:46:53.158282+00'),
('a11', 'arte', null, 'Tecidos têxteis', 'Daniel Rock', '"Tecidos Têxteis", de Daniel Rock, é um catálogo descritivo escrito no final do século XIX. A obra concentra-se em uma coleção de vestes litúrgicas, vestidos, tecidos de seda, bordados e tapeçarias pertencentes ao Museu de South Kensington. O livro oferece informações sobre a história, as técnicas e o significado cultural de diversos têxteis, examinando materiais como lã, seda e ouro, bem como suas origens geográficas e estilos. A abertura do catálogo apresenta ao leitor a extensa coleção e seu propósito. Enfatiza a relevância histórica dos têxteis, mostrando a evolução da tecelagem e o papel das mulheres nas artes têxteis em diversas culturas e épocas. Rock destaca a importância desses tecidos não apenas como itens funcionais, mas também como obras de arte, dignas de estudo por seu artesanato e qualidades estéticas. Ao descrever os materiais e métodos utilizados na criação dos têxteis, ele prepara o terreno para uma exploração mais aprofundada das diversas seções que se seguem no catálogo.', 'https://www.gutenberg.org/cache/epub/66172/pg66172.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/66172/pg66172-images.epub', null, null, true, false, null, null, true, '2026-05-27 23:48:50.991178+00', '2026-05-27 23:48:50.991178+00'),
('a12', 'arte', null, 'Mulher como Decoração', 'Emily Burbank', '"A Mulher como Decoração", de Emily Burbank, é um guia sobre moda feminina e design de figurinos escrito no início do século XX. O livro explora a arte de se vestir bem, enfatizando o papel da mulher como elemento vital na composição decorativa de qualquer ambiente. Seu objetivo é fornecer às leitoras princípios para compreenderem seus próprios tipos físicos e como realçar sua aparência por meio da escolha adequada de roupas em diversos contextos. A introdução do livro apresenta a intenção da autora de estudar o contexto histórico do vestuário feminino, ao mesmo tempo que orienta mulheres modernas na criação de figurinos eficazes e decorativos para o dia a dia e ocasiões especiais. Burbank destaca a importância de compreender regras fundamentais sobre linhas, cores e adequação, com ênfase na compreensão do próprio tipo físico e no emprego de técnicas que valorizem os pontos fortes individuais. Ela também aborda os aspectos psicológicos das roupas, ilustrando como o vestuário pode influenciar o comportamento e a presença de uma mulher na sociedade. Em suma, a introdução prepara o terreno para uma exploração abrangente da moda como arte e meio de expressão pessoal.', 'https://www.gutenberg.org/cache/epub/18901/pg18901.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/18901/pg18901-images.epub', null, null, true, false, null, null, true, '2026-05-27 23:53:42.883592+00', '2026-05-27 23:53:42.883592+00'),
('a2', 'arte', null, 'História da Arte para Iniciantes e Estudantes: Pintura, Escultura, Arquitetura', 'Waters, Clara Erskine Clement', '"Uma História da Arte para Iniciantes e Estudantes: Pintura, Escultura, Arquitetura", de Clara Erskine Clement, é um guia didático sobre história da arte, escrito no final do século XIX. Este abrangente volume serve como recurso tanto para iniciantes quanto para estudantes de arte, abordando as principais formas de arte, como pintura, escultura e arquitetura, em diferentes culturas e épocas. O tema principal do livro concentra-se na evolução e em exemplos dessas formas de arte. O livro aborda diversas formas de arte, oferecendo perspectivas sobre seu contexto histórico e significado. A abertura introduz o tema da escultura antiga, começando pela arte egípcia. Discute as práticas e técnicas iniciais dos artistas egípcios, destacando figuras notáveis ​​como o escultor Martisen, e descreve as características únicas de suas esculturas, incluindo poses rígidas e ausência de movimento. Ilustrações de obras famosas como a Esfinge e os Colossos de Tebas são mencionadas, juntamente com discussões sobre as limitações e avanços na arte egípcia. Esta seção estabelece uma base para a compreensão dos capítulos subsequentes, que explorarão outras culturas, incluindo a escultura assíria e grega, marcando a jornada pela história da arte que o livro se propõe a apresentar.', 'https://www.gutenberg.org/cache/epub/25632/pg25632.cover.medium.jpg', null, 'free', null, 'https://www.gutenberg.org/cache/epub/25632/pg25632-images-3.epub', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-27 23:49:48.109764+00'),
('a3', 'arte', null, 'O livro completo de ópera', 'Gustav Kobbé', '"O livro completo de ópera", de Gustav Kobbé, é um guia de óperas publicado postumamente em 1919. Esta obra de referência abrangente apresenta histórias sobre óperas juntamente com a notação musical dos principais temas e motivos. Abrangendo obras de Gluck até compositores do início do século XX, o livro organiza as óperas por escolas nacionais e períodos históricos. Originalmente inacabado com a morte de Kobbé, foi concluído pela editora Katharine Wright e expandido em inúmeras edições, tornando-se o relato enciclopédico definitivo de ópera para gerações de amantes da música e colecionadores de discos.', 'https://www.gutenberg.org/cache/epub/40540/pg40540.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/40540/pg40540-images.epub', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-27 23:50:46.346831+00'),
('a4', 'arte', null, 'Minha Vida — Volume 1', 'Richard Wagner', '"Minha Vida — Volume 1", de Richard Wagner, é uma autobiografia escrita entre 1865 e 1880, que abrange sua vida desde o nascimento, em 1813, até 1864. Ditada à sua amante Cosima von Bülow a pedido do rei Luís II da Baviera, Wagner relata sua carreira tempestuosa, suas amizades e controvérsias com detalhes surpreendentemente francos. Originalmente impressa em edições limitadas para circulação privada, a autobiografia gerou rumores devido à sua disponibilidade restrita. A obra oferece um relato dinâmico e acessível do desenvolvimento de Wagner e do mundo musical de sua época, embora sua perspectiva subjetiva revele visões condescendentes em relação aos contemporâneos e ataques a compositores rivais.', 'https://www.gutenberg.org/cache/epub/5197/pg5197.cover.medium.jpg', null, 'free', null, 'https://www.gutenberg.org/cache/epub/5197/pg5197-images-3.epub', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-27 23:50:22.69237+00'),
('a5', 'arte', '53b76adb-b49c-4423-b738-e29099bf737e', 'Romance das Vilas Romanas (O Renascimento)', 'Elizabeth W. Champney', '"Romance das Vilas Romanas (O Renascimento)", de Elizabeth W. Champney, é um relato histórico escrito no início do século XX. A obra explora as grandiosas, porém frequentemente decadentes, vilas dos cardeais romanos durante o Renascimento, mergulhando em seu esplendor arquitetônico e na vida vibrante que outrora as preenchia. Champney concentra-se particularmente nas histórias intrigantes que cercam essas vilas, muitas vezes destacando as figuras notáveis ​​que as habitaram, incluindo artistas e nobres. No início do livro, o autor apresenta o contexto histórico das vilas pertencentes aos cardeais, refletindo sobre como sua grandeza se desvaneceu com o tempo, embora ainda conserve um charme singular. Os capítulos iniciais insinuam a vida de figuras proeminentes como Cesare Borgia e a da feroz e bela Caterina Sforza, cuja rebeldia personifica os conflitos dramáticos e as intrigas políticas da época. A narrativa entrelaça referências históricas com descrições evocativas das vilas, preparando o terreno para uma exploração fascinante da arte, do romance e da dinâmica social da Itália renascentista.', 'https://www.gutenberg.org/cache/epub/27766/images/ill_cover_th.png', null, null, null, 'https://www.gutenberg.org/cache/epub/27766/pg27766-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 23:11:51.042335+00', '2026-05-27 23:51:28.592878+00'),
('a6', 'arte', null, 'Estilo no canto', 'WE Haslam', '"Estilo no Canto", de W.E. Haslam, é um guia sobre técnicas vocais e arte vocal escrito no início do século XX. O texto aprofunda-se nos princípios do estilo vocal, explorando os elementos do canto e da interpretação eficazes. Haslam enfatiza a importância de técnicas fundamentais como emissão vocal, técnica, estilo e repertório, destacando as maneiras pelas quais esses componentes interagem harmoniosamente nas performances vocais. A abertura do livro apresenta a motivação do autor para suprir a falta de literatura abrangente sobre estilo vocal, semelhante às obras existentes para música instrumental, Haslam discute os efeitos emocionais consistentes que artistas renomados conseguem produzir por meio de suas performances, levantando questões sobre a natureza da expressão no canto. Ele descreve os elementos fundamentais do treinamento vocal, enfatizando a importância da colocação vocal correta, da técnica e do estilo pessoal, e alerta para os perigos de uma instrução inadequada. Ao estabelecer uma base sólida para o desenvolvimento de uma carreira de cantor, Haslam defende a necessidade de escolher um repertório apropriado que esteja em sintonia com a voz e o temperamento únicos do cantor.', 'https://www.gutenberg.org/cache/epub/21400/pg21400.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/21400/pg21400-images.epub', null, null, true, false, null, null, true, '2026-05-27 23:38:03.282458+00', '2026-05-27 23:49:05.483339+00'),
('a7', 'arte', null, 'Trajes de banho e natação femininos nos Estados Unidos', 'Claudia Brush Kidwell', '"Trajes de Banho e Natação Femininos nos Estados Unidos", de Claudia Brush Kidwell, é um relato histórico publicado no final do século XX. Esta obra traça a evolução dos trajes de banho femininos na América, desde suas origens utilitárias até designs mais funcionais e esteticamente agradáveis. O livro explora como as atitudes da sociedade em relação aos papéis das mulheres e à participação delas em atividades recreativas influenciaram a mudança nos estilos e padrões de modéstia em trajes de banho e natação trajes ao longo da história. A abertura do livro oferece uma introdução completa ao tema, discutindo como os trajes de banho femininos antigos eram inicialmente restritivos e utilitários, influenciados por normas de modéstia e expectativas sociais. Explica a transformação gradual dessas vestimentas, destacando a dinâmica cultural e os avanços tecnológicos que permitiram às mulheres maior liberdade e aceitação em atividades aquáticas. Kidwell prepara o terreno para uma exploração detalhada dessa evolução, observando que a história dos trajes de banho femininos está intrinsecamente ligada a temas mais amplos, como a percepção pública das mulheres, os movimentos de saúde e o avanço da igualdade de gênero em atividades recreativas.', 'https://www.gutenberg.org/cache/epub/37586/pg37586.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/37586/pg37586-images.epub', null, null, true, false, null, null, true, '2026-05-27 23:40:19.010969+00', '2026-05-27 23:40:19.010969+00'),
('a8', 'arte', null, 'Trajes: Fantasiosos, Históricos e Teatrais', 'Sra. Aria', '"Trajes: Fantasiosos, Históricos e Teatrais", da Sra. Aria, é uma compilação que se concentra na evolução das roupas e da moda ao longo de vários períodos históricos, escrita no início do século XX. A obra explora as complexidades do design de figurinos desde os tempos clássicos até as influências mais modernas, estabelecendo conexões entre as vestimentas e os contextos culturais. As ilustrações de Percy Anderson enriquecem o texto, exibindo os estilos e tendências vibrantes que definiram diferentes épocas . No início do livro, a autora apresenta o conceito de moda, observando seu alcance limitado na sociedade romana antiga, onde o vestuário era estritamente regulamentado por normas e leis sociais. Ela discute a toga e a túnica como vestimentas comuns, enfatizando a falta de individualidade na moda daquela época. O texto destaca a preferência de Boadicea por trajes romanos durante sua rebelião contra os romanos, estabelecendo um contexto histórico para a discussão sobre vestuário ao longo dos séculos. A narrativa da Sra. Aria é informativa e reflexiva, estabelecendo uma base para examinar a arte do vestuário em diversos capítulos, com foco em detalhes como tecidos, estilos e significado cultural.', 'https://www.gutenberg.org/cache/epub/48551/pg48551.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/48551/pg48551-images.epub', null, null, true, false, null, null, true, '2026-05-27 23:42:46.255317+00', '2026-05-27 23:42:46.255317+00'),
('a9', 'arte', null, 'Joias e a mulher: O romance, a magia e a arte do adorno feminino', 'Ostier', '"Joias e a Mulher: O Romance, a Magia e a Arte do Adorno Feminino", de Marianne Ostier, é um estudo abrangente sobre joias, escrito no final do século XX. A obra explora o significado histórico das joias, particularmente sua relação com a feminilidade e o adorno em diversas culturas e épocas. Provavelmente, entrelaça temas de romance, magia e expressão artística, destacando a importância das joias para realçar a beleza e o status social. A introdução do texto estabelece um tom reflexivo, discutindo a evolução cultural e histórica das joias e seu significado para as mulheres. O prefácio observa que, ao longo da história, as mulheres têm sido cada vez mais associadas ao adorno, contrastando com os papéis tradicionais dos homens em muitas sociedades. Discute a transição das joias de um domínio primordialmente masculino para um símbolo de feminilidade, beleza e expressão pessoal. A introdução também sugere uma exploração detalhada dos aspectos práticos e estéticos das joias, abordando temas que vão desde adornos antigos até as práticas modernas de fabricação de joias. O autor expressa uma profunda admiração pela beleza das joias e pelo seu poder de transmitir identidade pessoal e status social.', 'https://www.gutenberg.org/cache/epub/69046/pg69046.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/69046/pg69046-images.epub', null, null, true, false, null, null, true, '2026-05-27 23:45:07.400668+00', '2026-05-27 23:45:07.400668+00'),
('c1', 'ciencia', '52e14655-4552-4982-a94c-4d428bc76774', 'A Origem das Espécies', 'Charles Darwin', 'A obra fundamental da biologia moderna que revolucionou nossa compreensão da evolução e da diversidade da vida na Terra.', 'https://images.unsplash.com/photo-1532094349884-543bc11b234d?w=300&h=400&fit=crop', '🧬', 'free', '3.8MB', 'https://www.gutenberg.org/files/1228/1228-h/1228-h.htm', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-13 22:40:26.487036+00'),
('c2', 'ciencia', '73d0e286-7b54-44b9-8c26-86577acdd9e4', 'Uma Breve História do Tempo', 'Stephen Hawking', 'Uma jornada fascinante através do universo, desde o Big Bang até os buracos negros, explicada de forma acessível.', 'https://images.unsplash.com/photo-1446776653964-20c1d3a81b06?w=300&h=400&fit=crop', '🌌', 'free', '2.1MB', 'https://gutendex.com/books/1', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-13 22:40:26.487036+00'),
('c3', 'ciencia', '52e14655-4552-4982-a94c-4d428bc76774', 'O Gene Egoísta', 'Richard Dawkins', 'Uma exploração revolucionária da teoria da evolução através da perspectiva dos genes e sua influência no comportamento.', 'https://images.unsplash.com/photo-1576086213369-97a306d36557?w=300&h=400&fit=crop', '🧬', 'free', '2.9MB', 'https://gutendex.com/books/2', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-13 22:40:26.487036+00'),
('f1', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'A República de Platão', 'Platão', '"A República", de Platão, é um diálogo socrático escrito por volta de 375 a.C. Através de conversas entre Sócrates e vários atenienses, a obra explora o significado de justiça e se a pessoa justa é mais feliz do que a injusta. Sócrates examina as formas de governo existentes e propõe uma cidade-estado ideal governada por filósofos-reis. O diálogo aborda questões profundas: a natureza da alma, o papel da poesia, o amor, o envelhecimento e o propósito da política .', 'https://www.gutenberg.org/cache/epub/1497/pg1497.cover.medium.jpg', '🏛️', 'free', '1.5MB', 'https://www.gutenberg.org/cache/epub/1497/pg1497-images-3.epub', null, null, true, false, null, 0, true, '2026-05-13 22:28:08.812226+00', '2026-05-27 21:57:07.777883+00'),
('f10', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Walden e Sobre o Dever da Desobediência Civil,', 'Henry David Thoreau', 'Walden e Sobre o Dever da Desobediência Civil", de Henry David Thoreau, é um ensaio filosófico e uma crítica social escrita em meados do século XIX. Esta obra reflete as reflexões de Thoreau sobre a vida simples em meio à natureza, baseando-se em sua experiência pessoal de viver sozinho na floresta perto do lago Walden. Thoreau enfatiza temas como a autossuficiência, a crítica ao materialismo e a importância da consciência individual e da desobediência civil diante da injustiça ... Leia mais A abertura de "Walden" começa com Thoreau relatando seus dois anos de solidão em uma casa construída por ele mesmo às margens do lago Walden, onde viveu de forma simples e se dedicou ao trabalho braçal. Ele aborda a curiosidade dos moradores da cidade sobre suas escolhas de estilo de vida e apresenta suas opiniões sobre as pressões sociais que levam as pessoas a vidas de "desespero silencioso". Por meio de imagens vívidas e reflexões filosóficas, Thoreau discute o peso das posses herdadas e as expectativas da sociedade, afirmando que muitas pessoas vivem vidas sem reflexão. Ele clama por uma reavaliação do que é considerado necessário para uma vida plena, sugerindo que a verdadeira felicidade deriva da simplicidade, do pensamento individual e de uma conexão íntima com a natureza.', 'https://www.gutenberg.org/cache/epub/205/pg205.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/205/pg205-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:27:42.161833+00', '2026-05-27 22:27:42.161833+00'),
('f11', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'A Coroa da Oliveira Selvagem,', 'John Ruskin', 'A Coroa da Oliveira Selvagem", de John Ruskin, é uma coletânea de palestras escritas no final do século XIX, que abordam questões sociais cruciais da época, em particular os conceitos de trabalho, comércio e guerra. Nela, Ruskin explora as implicações morais e sociais da industrialização e do capitalismo, questionando o verdadeiro valor do trabalho e clamando por uma reavaliação das formas como a sociedade direciona o esforço humano. A obra serve como ... Leia mais Uma denúncia e uma exploração filosófica das condições dos trabalhadores e das responsabilidades éticas dos ricos. O início do texto apresenta as reflexões de Ruskin sobre a bela, porém tragicamente negligenciada, paisagem rural inglesa, que ele vê como uma representação das consequências do descaso industrial pela natureza e pela dignidade humana. Ele lamenta a poluição e o desperdício resultantes dos empreendimentos capitalistas, enfatizando que a destruição física espelha uma decadência moral mais profunda na sociedade. Ruskin prepara o terreno para suas palestras questionando as prioridades tanto no capitalismo quanto no trabalho individual, postulando que a busca pela riqueza muitas vezes leva à perda do verdadeiro valor e da alegria na vida. Esta parte inicial serve para envolver os leitores com temas imediatos e relevantes de justiça ambiental e social, lançando as bases para as discussões mais complexas que se seguem', 'https://www.gutenberg.org/cache/epub/26716/pg26716.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/26716/pg26716-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:30:40.10571+00', '2026-05-27 22:30:40.10571+00'),
('f12', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Além do Bem e do Mal', 'Friedrich Wilhelm Nietzsche', 'Além do Bem e do Mal", de Friedrich Wilhelm Nietzsche, é uma obra filosófica publicada em 1886. Nietzsche lança um ataque feroz à filosofia tradicional, acusando pensadores do passado de disfarçarem preconceitos morais como verdades objetivas. Ele desafia conceitos fundamentais como bem versus mal, conhecimento e livre-arbítrio, propondo, em vez disso, sua teoria da "vontade de poder". O livro clama por novos filósofos que transcendam a moralidade convencional para abraçar uma compreensão mais ousada e perspectivista ... Leia mais da existência e criar novos valores para o futuro.', 'https://www.gutenberg.org/cache/epub/4363/pg4363.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/4363/pg4363-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:32:46.919258+00', '2026-05-27 22:32:46.919258+00'),
('f13', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'A Moral de Plutarco', 'Plutarco', 'Os Costumes de Plutarco", de Plutarco, é uma coletânea de ensaios e discursos escritos no século I. Esta obra eclética contém 78 textos que exploram a vida romana e grega, além de observações filosóficas atemporais. De discussões sobre Alexandre, o Grande, e ritos religiosos egípcios a reflexões sobre justiça divina e paz de espírito, a coletânea abrange desde tratados sérios a diálogos bem-humorados. Esses ensaios influenciaram profundamente o pensamento europeu por gerações, moldando os humanistas do Renascimento e o Iluminismo', 'https://www.gutenberg.org/cache/epub/23639/pg23639.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/23639/pg23639-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:34:37.085642+00', '2026-05-27 22:34:37.085642+00'),
('f14', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Ecce Homo', 'Friedrich Wilhelm Nietzsche', 'Ecce Homo", de Friedrich Wilhelm Nietzsche, é uma autobiografia filosófica escrita em 1888. Nesta obra final e provocativa, Nietzsche oferece sua própria interpretação de sua vida, filosofia e significado por meio de capítulos com títulos ousados ​​como "Por que sou tão sábio" e "Por que escrevo livros tão bons". Ele revisa suas principais obras, apresenta uma nova imagem do filósofo dionisíaco e desafia a moralidade do cristianismo. Escrito com hipérbole característica e ironia autoconsciente, o livro ... Leia mais Coloca o próprio Nietzsche em julgamento ao mesmo tempo que declara sua visão para o futuro da humanidade.', 'https://www.gutenberg.org/cache/epub/52190/pg52190.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/52190/pg52190-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:37:40.462655+00', '2026-05-27 22:44:43.068152+00'),
('f15', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Um Picles para os Sábios', 'Timothy Dexter', 'Um Picles para os Sábios", de Timothy Dexter, é um livro autobiográfico publicado em 1802. Esta obra excêntrica contém quase nenhuma pontuação, ortografia pouco ortodoxa e gramática caótica em todas as suas páginas. O rico empresário americano divaga sobre políticos e clérigos enquanto exalta sua própria glória e sugere que deveria ser imperador dos Estados Unidos. Após reclamações sobre a falta de pontuação, Dexter adicionou uma segunda edição com páginas de sinais de pontuação no início e no final . apêndice, convidando os leitores a utilizá-los como bem entenderem', 'https://www.gutenberg.org/cache/epub/43453/pg43453.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/43453/pg43453-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:43:07.722805+00', '2026-05-27 22:43:07.722805+00'),
('f16', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Os Novos Ensaios de Leibniz sobre o Entendimento Humano: Uma Exposição Crítica', 'Dewey, John', 'Novos Ensaios de Leibniz sobre o Entendimento Humano: Uma Exposição Crítica", de John Dewey, é um tratado filosófico escrito no final do século XIX. Esta obra explora criticamente as ideias de Gottfried Wilhelm Leibniz, com foco particular em suas perspectivas nos "Novos Ensaios" e examinando os fundamentos do entendimento humano através da filosofia racionalista. O texto busca conectar o pensamento de Leibniz com as discussões filosóficas contemporâneas, destacando a importância de suas ideias na evolução ... Leia mais do pensamento moderno. A abertura da obra apresenta um esboço biográfico de Leibniz, ilustrando as experiências formativas que moldaram suas buscas filosóficas. Dewey discute a educação inicial e o desenvolvimento intelectual de Leibniz, enfatizando as influências de sua família, mentores e encontros significativos com pensadores contemporâneos. A narrativa percorre a trajetória acadêmica de Leibniz, destacando suas incursões em múltiplas disciplinas, incluindo direito, matemática e filosofia, como uma busca por uma compreensão harmoniosa do universo, que prenuncia suas contribuições filosóficas posteriores. Essa exposição serve como base para uma exploração mais profunda do pensamento de Leibniz e seu impacto duradouro na filosofia e na ciência.', 'https://www.gutenberg.org/cache/epub/40957/pg40957.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/40957/pg40957-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:47:04.442183+00', '2026-05-27 22:47:04.442183+00'),
('f17', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'O Enchiridion de Epicteto', 'Epicteto', 'O Enquirídio", de Epicteto, é um manual de conselhos éticos estoicos compilado no início do século II por Arriano, um discípulo do filósofo grego. Este conciso guia destila preceitos práticos para alcançar a liberdade mental e a felicidade em todas as circunstâncias. Ensina os leitores a distinguir entre o que está sob seu controle e o que não está, enfatizando que os julgamentos, e não os eventos externos, perturbam as pessoas. Através de imagens vívidas e exemplos do cotidiano, a obra guia ... Leia mais Capacitar os alunos para que prosperem tanto em situações favoráveis ​​quanto adversas, desenvolvendo as capacidades do espírito humano.', 'https://www.gutenberg.org/cache/epub/45109/pg45109.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/45109/pg45109-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:49:24.522983+00', '2026-05-27 22:49:24.522983+00'),
('f18', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Simpósio de Platão', 'Platão', 'O Banquete", de Platão, é um diálogo socrático escrito entre 385 e 370 a.C. Em um banquete na Atenas antiga, figuras notáveis ​​como Sócrates, Alcibíades e Aristófanes participam de uma competição de discursos em louvor a Eros, o deus do amor. Cada um oferece sua perspectiva sobre a natureza e o poder do amor — desde inspirar coragem no campo de batalha até transcender o desejo terreno. Através de ideias conflitantes e pontos de vista divergentes, o diálogo explora os significados mais profundos do amor, demonstrando tanto profundidade filosófica quanto talento literário', 'https://www.gutenberg.org/cache/epub/1600/pg1600.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/1600/pg1600-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:51:54.476871+00', '2026-05-27 22:51:54.476871+00'),
('f19', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Segundo Tratado sobre o Governo Civil,', 'John Locke', 'O Segundo Tratado sobre o Governo Civil", de John Locke, é uma obra de filosofia política publicada em 1689. Escrito anonimamente durante a turbulenta revolução inglesa, Locke delineia uma visão radical da sociedade, fundada nos direitos naturais e no governo por consentimento, em vez de autoridade divina. Suas ideias desafiam a ordem estabelecida, argumentando que o poder legítimo emana do povo, e não de reis que reivindicam um governo concedido por Deus. Este texto fundamental da teoria política liberal emergiu de conspirações perigosas e do exílio', 'https://www.gutenberg.org/cache/epub/7370/pg7370.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/7370/pg7370-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:56:29.610078+00', '2026-05-27 22:56:29.610078+00'),
('f2', 'filosofia', 'c333dcc2-bcea-42ac-a612-764ee66c0806', 'A Cidade de Deus, Volume I, de Santo Agostinho de Hipona', 'Santo Agostinho de Hipona', '"A Cidade de Deus, Volume I", do bispo de Hipona, Santo Agostinho, é uma obra de filosofia cristã escrita em latim no início do século V d.C. Composta em resposta ao saque de Roma pelos visigodos em 410, Agostinho defende o cristianismo contra as acusações de que este teria causado a decadência de Roma. Ele apresenta a história da humanidade como um conflito entre a Cidade Terrena — aqueles que buscam os prazeres mundanos — e a Cidade de Deus — aqueles dedicados às verdades eternas. Através de reflexões teológicas ... Leia mais Em sua argumentação e análise histórica, Agostinho refuta a religião e a filosofia pagãs, ao mesmo tempo que discorre sobre o sofrimento, o mal, o livre-arbítrio e o pecado original.', 'https://www.gutenberg.org/cache/epub/45304/pg45304.cover.medium.jpg', '⚖️', 'free', '1.2MB', 'https://www.gutenberg.org/cache/epub/45304/pg45304-images-3.epub', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-27 22:03:34.470437+00'),
('f20', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'As Vidas e Opiniões de Filósofos Eminentes', 'Diógenes Laércio', 'As Vidas e Opiniões de Filósofos Eminentes", de Diógenes Laércio, é uma compilação de relatos históricos e esboços biográficos escritos no final do século II d.C. Esta extensa obra narra as vidas e filosofias de vários filósofos gregos notáveis, oferecendo insights sobre seus pensamentos, contribuições e contextos. O texto serve como uma fonte crucial de informação sobre a história da filosofia grega, ligando o surgimento do pensamento filosófico a figuras proeminentes como ... Leia mais Tales, Sólon e Sócrates. No início desta obra, o autor apresenta uma introdução que descreve as origens e classificações da filosofia, distinguindo entre as influências das tradições gregas e não gregas. Diógenes Laércio discute as primeiras figuras da filosofia e prepara o terreno para uma exploração mais detalhada de filósofos notáveis, começando especificamente por Tales. A parte introdutória apresenta a estrutura da obra, destacando a importância dos ensinamentos filosóficos e o impacto dos primeiros filósofos no pensamento subsequente, conduzindo, em última análise, a uma análise mais profunda da vida desses pensadores influentes.', 'https://www.gutenberg.org/cache/epub/57342/pg57342.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/57342/pg57342-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 23:00:29.150797+00', '2026-05-27 23:02:16.097783+00'),
('f3', 'filosofia', '177ce7b2-b2fd-4d73-b474-8730f46fa3bb', 'Lições de Hegel sobre a História da Filosofia', 'Hegel, Georg Wilhelm Friedrich', 'Palestras de Hegel sobre a História da Filosofia: Volume 3", de Hegel, é uma obra filosófica escrita no final do século XIX. Este volume continua a exploração do desenvolvimento do pensamento filosófico através de várias épocas históricas, com ênfase particular na Idade Média e no surgimento da filosofia moderna. O texto reflete sobre a evolução das ideias, focando na influência do cristianismo na filosofia, na importância dos pensadores medievais e ... Leia mais transição para estruturas filosóficas mais modernas. No início do volume, Hegel apresenta o contexto histórico da filosofia medieval, abrangendo um milênio, desde os primeiros pensadores gregos, como Tales, até o declínio da filosofia pagã. Ele descreve o papel do pensamento neoplatônico na formação da ideologia cristã primitiva, enfatizando a interação entre a natureza divina e a humana. Hegel discute as contribuições de filósofos árabes e judeus, que preservaram e expandiram o pensamento grego. Essa abertura prepara o terreno para um exame detalhado de tradições filosóficas específicas, a integração de ideias religiosas na filosofia e os desafios apresentados por filosofias emergentes que, eventualmente, moldariam o panorama filosófico moderno', 'https://www.gutenberg.org/cache/epub/58169/pg58169.cover.medium.jpg', '🔍', 'free', '0.9MB', 'https://www.gutenberg.org/cache/epub/58169/pg58169-images-3.epub', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-27 22:01:01.168251+00'),
('f4', 'filosofia', '2118318e-42a5-4799-a1f6-8ce295a18b93', 'Meditações de Marco Aurélio', 'Marco Aurélio', 'Meditações", do Imperador Romano Marco Aurélio, é uma série de escritos pessoais compostos entre 170 e 180 d.C. Escrita em grego como anotações particulares para si mesmo, esta obra captura as reflexões do imperador romano sobre a filosofia estoica e o aprimoramento pessoal durante campanhas militares. Nunca destinadas à publicação, essas reflexões íntimas exploram a busca do próprio lugar no universo, a manutenção de princípios éticos e a conquista da harmonia interior por meio da razão. Os doze livros revelam como um dos personagens mais importantes da história ... Leia mais Governantes poderosos buscavam moldar seu próprio caráter e julgamento', 'https://www.gutenberg.org/cache/epub/2680/pg2680.cover.medium.jpg', '🤝', 'free', '1.3MB', 'https://www.gutenberg.org/cache/epub/2680/pg2680-images-3.epub', null, null, true, false, null, null, true, '2026-05-13 22:28:08.812226+00', '2026-05-27 22:07:04.731587+00'),
('f5', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Assim Falou Zaratustra: Um Livro para Todos e para Ninguém', 'Friedrich Wilhelm Nietzsche', 'Assim Falou Zaratustra: Um Livro para Todos e para Ninguém", de Friedrich Wilhelm Nietzsche, é uma obra de ficção filosófica publicada entre 1883 e 1885. Através da voz do antigo profeta Zaratustra, Nietzsche discorre sobre temas que vão do mundano ao metafísico. A obra introduz conceitos centrais de Nietzsche, incluindo o Übermensch (super-homem), a morte de Deus, a vontade de poder e o eterno retorno. Escrita em linguagem analógica e figurativa, a obra surgiu ... Leia mais fruto de décadas de experiência acumulada durante caminhadas solitárias nas montanhas.', 'https://www.gutenberg.org/cache/epub/1998/pg1998.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/1998/pg1998-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:16:46.430506+00', '2026-05-27 22:16:46.430506+00'),
('f6', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'O Príncipe', 'Nicolau Maquiavel', 'O Príncipe", de Nicolau Maquiavel, é um tratado político escrito em 1513 e publicado em 1532. Apresentado como um guia para novos governantes, esta obra controversa sugere que atos imorais podem ser necessários para alcançar poder e glória política. Escrito em italiano vernáculo, em vez de latim, rompe com a literatura tradicional de conselhos ao focar na eficácia prática em vez de ideais abstratos. Sua visão de mundo desafiou as doutrinas católicas dominantes da época, tornando-se "maquiavélica" ... Leia mais Sinônimo de astúcia política e contribuindo para as conotações negativas modernas da própria política.', 'https://www.gutenberg.org/cache/epub/1232/pg1232.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/1232/pg1232-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:18:39.3706+00', '2026-05-27 22:18:39.3706+00'),
('f7', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'O Kama Sutra de Vatsyayana', 'Vatsyayana', 'O Kama Sutra de Vatsyayana", de Vatsyayana, é um antigo texto sânscrito composto entre os séculos III e V d.C. Mais do que um simples manual sobre posições sexuais, esta obra hindu explora a arte de viver bem, abrangendo o namoro, a satisfação emocional, a manutenção de relacionamentos e a filosofia do desejo. Integrando o conceito hindu mais amplo dos objetivos adequados da vida, aborda quando o desejo sustenta a felicidade e como o prazer se encaixa em uma existência significativa. ... Leia mais O texto combina versos aforísticos concisos com prosa, oferecendo orientação sobre a natureza do amor e a busca pela satisfação.', 'https://www.gutenberg.org/cache/epub/27827/pg27827.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/27827/pg27827-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:21:12.783373+00', '2026-05-27 22:21:12.783373+00'),
('f8', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'O Homem Que Era Quinta-Feira: Um Pesadelo, de G.K. Chesterton', 'G.K. Chesterton', 'O Homem que Era Quinta-Feira: Um Pesadelo", de G.K. Chesterton, é um romance filosófico com elementos de aventura e sátira, escrito no final do século XIX. A história gira em torno do enigmático personagem Gabriel Syme, um detetive da polícia que se infiltra em um grupo de anarquistas em Londres para desvendar seus planos e identidades. Conforme a narrativa se desenrola, explora temas complexos como ordem, caos e a natureza do mal, frequentemente através de um humor sagaz ... Leia mais Diálogos e situações absurdas desafiam o pensamento convencional. No início do romance, os leitores são apresentados ao subúrbio de Saffron Park, com seus habitantes coloridos e excêntricos, principalmente poetas e artistas. Certa noite, durante um pôr do sol deslumbrante, o poeta anarquista Lucian Gregory conhece Gabriel Syme, que o surpreende com argumentos ousados ​​em favor da lei e da ordem, desafiando as visões de Gregory. A conversa entre eles se transforma em um duelo de ideologias quando Gregory revela seu profundo comprometimento com o anarquismo, o que leva a um confronto. Em uma reviravolta do destino, a verdadeira identidade de Syme como detetive é revelada, e, ao se juntar aos anarquistas disfarçado como um deles, o cenário está pronto para uma profunda exploração do conflito filosófico entre caos e estrutura na sociedade', 'https://www.gutenberg.org/cache/epub/1695/pg1695.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/1695/pg1695-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:23:11.397234+00', '2026-05-27 22:23:11.397234+00'),
('f9', 'filosofia', 'c1c31f07-a73f-4a44-b559-ec3826c2b2f0', 'Leviatã', 'Thomas Hobbes', 'Leviatã", de Thomas Hobbes, é um tratado filosófico publicado em 1651. Escrito durante a Guerra Civil Inglesa, explora a estrutura da sociedade e o governo legítimo através da teoria do contrato social. Hobbes argumenta que o estado natural da humanidade é uma brutal "guerra de todos contra todos", impulsionada por desejos individuais e pelo medo da morte violenta. Somente um soberano forte e absoluto pode prevenir a guerra civil e o caos, unindo o poder secular e o espiritual. ... Leia mais Esta obra influente apresenta uma visão materialista da natureza humana e da ordem política.', 'https://www.gutenberg.org/cache/epub/3207/pg3207.cover.medium.jpg', null, null, null, 'https://www.gutenberg.org/cache/epub/3207/pg3207-images-3.epub', null, null, true, false, null, null, true, '2026-05-27 22:24:57.212403+00', '2026-05-27 22:25:31.348516+00'),
